  const transcript: string[] = [];
  const state: ConquerState = { turn: 0, spentUsd: 0, startedAtMs: Date.now(), consults: 0 };

  let prompt = opts.task;
  let done = false;
  let lastClaim = '';
  let doneReason = '';
